package com.example.lessondesign.controller; import com.example.lessondesign.bean.TeacherDesign; import com.example.lessondesign.dao.TeacherDesignDao; import org.springframework.beans.factory.annotation.Autowired; import org.springframework.http.ResponseEntity; import org.springframework.web.bind.annotation.*; import java.util.*; @RestController @RequestMapping("/api/teaching-design") public class TeacherDesignController { @Autowired private TeacherDesignDao teacherDesignDao; @PostMapping("/save") public ResponseEntity<Map<String,Object>> save(@RequestBody TeacherDesign d){ Map<String,Object> r=new HashMap<>(); d.setCreatedTime(new Date()); int ok=teacherDesignDao.insert(d); r.put("success",ok>0);r.put("id",d.getId()); return ResponseEntity.ok(r); } @GetMapping("/teacher/{tid}") public ResponseEntity<List<TeacherDesign>> getByTeacher(@PathVariable String tid){ return ResponseEntity.ok(teacherDesignDao.findByTeacherId(tid)); } }